/**
 * Package documentation. Synchronize or validate the README rules table from
 * canonical rule metadata.
 */
// @ts-check

import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";
import { fileURLToPath } from "node:url";

// @ts-ignore -- Generated by the build; this script intentionally validates built output.
import builtPlugin from "../dist/plugin.js";
import { preferredRuleOrder } from "./_internal/preferred-rule-order.mjs";
const stylelint2ConfigMetadataByName = {
    all: { icon: "🟣" },
    configuration: { icon: "🔧" },
    recommended: { icon: "🟡" },
    stylelintOnly: { icon: "🎨" },
};
/** @type {readonly (keyof typeof presetDocsByName)[]} */
const stylelint2ConfigNamesByReadmeOrder = [
    "recommended",
    "stylelintOnly",
    "configuration",
    "all",
];
const stylelint2ConfigReferenceToName = {
    "stylelint2.configs.all": "all",
    "stylelint2.configs.configuration": "configuration",
    "stylelint2.configs.configs": "configuration",
    "stylelint2.configs.recommended": "recommended",
    "stylelint2.configs.stylelintOnly": "stylelintOnly",
    "stylelint2.configs.stylesheets": "stylelintOnly",
};
const presetDocsByName = {
    all: {
        href: "./docs/rules/presets/all.md",
        publicName: "stylelint2.configs.all",
    },
    configuration: {
        href: "./docs/rules/presets/configuration.md",
        publicName: "stylelint2.configs.configuration",
    },
    recommended: {
        href: "./docs/rules/presets/recommended.md",
        publicName: "stylelint2.configs.recommended",
    },
    stylelintOnly: {
        href: "./docs/rules/presets/stylelint-only.md",
        publicName: "stylelint2.configs.stylelintOnly",
    },
};

/**
 * @param {keyof typeof presetDocsByName} presetName
 *
 * @returns {string}
 *
 * @throws {Error} When the operation fails.
 */
const toPresetLegendLine = (presetName) => {
    const preset = presetDocsByName[presetName];
    const icon = stylelint2ConfigMetadataByName[presetName]?.icon;

    if (preset === undefined || icon === undefined) {
        throw new TypeError(`Unknown preset '${presetName}'.`);
    }

    return `- [\`${icon}\`](${preset.href}) — [\`${preset.publicName}\`](${preset.href})`;
};

const rulesSectionHeading = "## Rules";

/** @param {string} markdown */
const detectLineEnding = (markdown) =>
    markdown.includes("\r\n") ? "\r\n" : "\n";

/** @param {string} value */
const normalizeLineEndings = (value) => value.replaceAll("\r\n", "\n");

/** @param {string} markdown */
const normalizeMarkdownTableSpacing = (markdown) =>
    normalizeLineEndings(markdown)
        .split("\n")
        .map((line) => {
            const trimmedLine = line.trimEnd();
            const isTableRow = /^\|.*\|$/v.test(trimmedLine);

            if (!isTableRow) {
                return trimmedLine;
            }

            const cells = trimmedLine
                .split("|")
                .slice(1, -1)
                .map((cell) => {
                    const trimmedCell = cell.trim();
                    const isSeparatorCell = /^:?-+:?$/v.test(trimmedCell);
                    const hasStartColon = trimmedCell.startsWith(":");
                    const hasEndColon = trimmedCell.endsWith(":");

                    if (!isSeparatorCell) {
                        return trimmedCell;
                    }

                    if (hasStartColon && hasEndColon) {
                        return ":-:";
                    }

                    if (hasStartColon) {
                        return ":--";
                    }

                    if (hasEndColon) {
                        return "--:";
                    }

                    return "---";
                });

            return `| ${cells.join(" | ")} |`;
        })
        .join("\n")
        .trim();

/**
 * @param {string} markdown
 *
 * @returns {{ startOffset: number; endOffset: number }}
 *
 * @throws {Error} When the operation fails.
 */
const getRulesSectionBounds = (markdown) => {
    const startOffset = markdown.indexOf(rulesSectionHeading);

    if (startOffset < 0) {
        throw new Error("README.md is missing the '## Rules' section heading.");
    }

    const nextHeadingOffset = markdown.indexOf(
        "\n## ",
        startOffset + rulesSectionHeading.length
    );

    return {
        endOffset: nextHeadingOffset < 0 ? markdown.length : nextHeadingOffset,
        startOffset,
    };
};

/** @param {string} markdown */
export const extractReadmeRulesSection = (markdown) => {
    const { endOffset, startOffset } = getRulesSectionBounds(markdown);

    return markdown.slice(startOffset, endOffset);
};

/** @param {readonly string[] | string | undefined} configs */
const normalizeConfigNames = (configs) => {
    const values = Array.isArray(configs) ? configs : [configs];
    const normalized = [];

    for (const value of values) {
        if (typeof value !== "string") {
            continue;
        }

        if (Object.hasOwn(stylelint2ConfigReferenceToName, value)) {
            const referenceKey =
                /** @type {keyof typeof stylelint2ConfigReferenceToName} */ (
                    value
                );

            normalized.push(stylelint2ConfigReferenceToName[referenceKey]);
        }
    }

    return [...new Set(normalized)];
};

/**
 * @typedef {object} RuleMeta
 *
 * @property {string | undefined} [fixable] Rule fixability flag from metadata.
 * @property {{ configs?: readonly string[] | string } | undefined} [docs] Rule
 *   docs metadata.
 */

/**
 * @typedef {object} RuleModule
 *
 * @property {RuleMeta | undefined} [meta] Rule metadata container.
 */

/** @param {RuleModule} ruleModule */
const getRuleFixIndicator = (ruleModule) =>
    ruleModule.meta?.fixable === "code" ? "🔧" : "—";

/** @param {RuleModule} ruleModule */
const getPresetIndicator = (ruleModule) => {
    const configNames = new Set(
        normalizeConfigNames(ruleModule.meta?.docs?.configs)
    );

    const icons = [];

    for (const configName of stylelint2ConfigNamesByReadmeOrder) {
        if (!configNames.has(configName)) {
            continue;
        }

        const metadataKey =
            /** @type {keyof typeof stylelint2ConfigMetadataByName} */ (
                configName
            );
        const presetLink = /** @type {keyof typeof presetDocsByName} */ (
            configName
        );

        icons.push(
            `[${stylelint2ConfigMetadataByName[metadataKey].icon}](${presetDocsByName[presetLink].href})`
        );
    }

    return icons.join(" ");
};

/**
 * @param {[
 *     string,
 *     {
 *         meta?: {
 *             docs?: { url: string; configs?: readonly string[] | string };
 *             fixable?: string;
 *         };
 *     },
 * ]} entry
 *
 * @throws {Error} When the operation fails.
 */
const toRuleTableRow = ([ruleName, ruleModule]) => {
    const docsUrl = ruleModule.meta?.docs?.url;

    if (typeof docsUrl !== "string") {
        throw new TypeError(`Rule '${ruleName}' is missing meta.docs.url.`);
    }

    return `| [\`${ruleName}\`](${docsUrl}) | ${getRuleFixIndicator(ruleModule)} | ${getPresetIndicator(ruleModule)} |`;
};

/**
 * @param {Readonly<
 *     Record<
 *         string,
 *         {
 *             meta?: {
 *                 docs?: { url: string; configs?: readonly string[] | string };
 *                 fixable?: string;
 *             };
 *         }
 *     >
 * >} rules
 */
export const generateReadmeRulesSectionFromRules = (rules) => {
    const ruleEntries = Object.entries(rules).toSorted(([left], [right]) => {
        const leftIndex = preferredRuleOrder.indexOf(left);
        const rightIndex = preferredRuleOrder.indexOf(right);

        if (leftIndex >= 0 && rightIndex >= 0) {
            return leftIndex - rightIndex;
        }

        if (leftIndex >= 0) {
            return -1;
        }

        if (rightIndex >= 0) {
            return 1;
        }

        return left.localeCompare(right);
    });

    return [
        "## Rules",
        "",
        "Fix legend:",
        "",
        "- `🔧` = autofixable",
        "- `—` = report only",
        "",
        "Preset key legend:",
        "",
        ...stylelint2ConfigNamesByReadmeOrder.map(
            /** @param {keyof typeof presetDocsByName} presetName */
            (presetName) => toPresetLegendLine(presetName)
        ),
        "",
        "| Rule | Fix | Preset key |",
        "| --- | :-: | :-- |",
        ...ruleEntries.map(toRuleTableRow),
        "",
    ].join("\n");
};

export const syncReadmeRulesTable = async ({ writeChanges = false } = {}) => {
    const readmePath = resolve("README.md");
    const readmeMarkdown = await readFile(readmePath, "utf8");
    const lineEnding = detectLineEnding(readmeMarkdown);
    const expectedSection = generateReadmeRulesSectionFromRules(
        /**
         * @type {Readonly<
         *     Record<
         *         string,
         *         {
         *             meta?: {
         *                 docs?: {
         *                     url: string;
         *                     configs?: readonly string[] | string;
         *                 };
         *                 fixable?: string;
         *             };
         *         }
         *     >
         * >}
         */ (builtPlugin.rules)
    )
        .replace(/\n/gv, lineEnding)
        .trimEnd();
    const { endOffset, startOffset } = getRulesSectionBounds(readmeMarkdown);
    const currentSection = readmeMarkdown
        .slice(startOffset, endOffset)
        .trimEnd();

    if (
        normalizeMarkdownTableSpacing(currentSection) ===
        normalizeMarkdownTableSpacing(expectedSection)
    ) {
        return { changed: false };
    }

    if (!writeChanges) {
        throw new Error(
            "README rules table is out of sync with plugin metadata."
        );
    }

    const updatedReadme = `${readmeMarkdown.slice(0, startOffset)}${expectedSection}${readmeMarkdown.slice(endOffset)}`;
    await writeFile(readmePath, updatedReadme, "utf8");

    return { changed: true };
};

const currentEntryPath = process.argv[1];

if (
    typeof currentEntryPath === "string" &&
    fileURLToPath(import.meta.url) === resolve(currentEntryPath)
) {
    await syncReadmeRulesTable({
        writeChanges: process.argv.includes("--write"),
    });
}
